  // =========================================================================
  // class_recursive_refs
  // =========================================================================
  test("class_recursive_refs".fail) {
    assertCompresses(
      input = """class a {
          set() {
            class b {
              set [b] (c) {}
            }
          }
        }

        class b {
            constructor() {
                b();
            }
        }

        class c {
            [c] = 42;
        }

        class d {
            dee = d;
        }

        class e {
            static eee = e;
        }""".stripMargin.trim,
      expected = "",
      options = AllOff.copy(
        toplevel = ToplevelConfig(funcs = true, vars = true)
      )
    )
  }

  // =========================================================================
