  test("class_duplication".fail) {
    assertCompresses(
      input = """class Foo {
            foo() {
                leak(new Foo())
            }
        }

        // Export the class.
        export default Foo""".stripMargin.trim,
      expected = """class Foo {
            foo() {
                leak(new Foo())
            }
        }

        // Export the class.
        export default Foo""".stripMargin.trim,
      options = AllOff.copy(
        toplevel = ToplevelConfig(funcs = true, vars = true)
      )
    )
  }

