                return "S"
            }
            async print() {
                console.log(this.#method() + (await A.#method2().next()).value + this["#method"]());
            }
        }
        new A().print()""".stripMargin.trim,
      expected = """class A {
            #method() {
                return "PA"
            }
            static async* #method2() {
                return "S"
            }
            ["#method"]() {
                return "S"
            }
            async print() {
